-----------------------------------------------------------------
---巡逻行为
-----------------------------------------------------------------
---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdlePatrolAction:LFightIdleBaseAction
local LFightIdlePatrolAction = LxClass("LFightIdlePatrolAction",LFightIdleBaseAction)
-----------------------------------------------------------------
LFightIdlePatrolAction.PHASE_IDLE = 0 -- 0休息
LFightIdlePatrolAction.PHASE_MOVE = 1 -- 1 行走

function LFightIdlePatrolAction:LFightIdlePatrolAction()
	self._action = LFightIdleConst.ACTION_PATROL

	self._waitTime = 0

	self._phase = LFightIdlePatrolAction.PHASE_IDLE -- 0 休息 1 行走,巡逻是由行走和休息构成

	self._nextScanTime = 0

	self._scanInterval = 0.2

	self._limitArea = nil
end

-----------------------------------------------------------------
function LFightIdlePatrolAction:OnRun(time)
	if self._nextScanTime < time then
		if(self:DoScan()) then
			return
		end
	end

	if self._phase == LFightIdlePatrolAction.PHASE_MOVE then
		local actor = self._obj:GetMoveActor()
		if not actor:IsMoving() then
			self:GoToWait()
		end
	elseif self._phase == LFightIdlePatrolAction.PHASE_IDLE then
		if self._waitTime <= time then
			self:GotoPatrol()
		end
	end
end

function LFightIdlePatrolAction:DoScan()
	self._nextScanTime = self:GetTime() + self._scanInterval
	local objCtr =self:GetObjCtrl()

	local obj = self._obj
	if obj:GetObjType() == LFightIdleConst.OBJ_MISSION then
		return false
	end

	local side = obj:GetSide()
	local teamList = objCtr:GetOppositeTeamBySide(side)
	local bHave = false
	local boardRefId = obj:GetBoardRefId()

	local nowPos = obj:GetPosition()
	local atkDis = obj:GetAtkDis()
	for k,v in ipairs(teamList) do
		if v:GetBoardRefId() == boardRefId and v:IsLive() and v:IsReady() and self:CheckInAtk(v,nowPos,atkDis) then
			bHave = true
			break
		end
	end
	if bHave then
		local ai = self._ai
		if (not ai:IsHaveAction(LFightIdleConst.ACTION_ATK)) then
			return false
		end
		if obj:SetStatus(LFightIdleConst.STATUS_IDLE) then
			obj:GetMoveActor():StopMove()
			obj:PlayIdleAni()
		end
		ai:ChangeAction(LFightIdleConst.ACTION_ATK)
		return true
	end
	return false
end

function LFightIdlePatrolAction:CheckInAtk(tarObj,nowPos,atkDis)
	local tarBodyX = tarObj:GetBodyX()
	local tarPos = tarObj:GetPosition()
	local distance = Mathf.Abs(tarPos.x - nowPos.x)
	local realAtkDis = tarBodyX + atkDis
	if LFightIdleConst.Approximately(distance,realAtkDis) or distance < realAtkDis then
		return true
	end
	return false
end

function LFightIdlePatrolAction:CheckInLimitArea(limitArea,pos)
	if pos.x < limitArea.min  or  pos.x > limitArea.max then
		return false
	end
	return true
end
-----------------------------------------------------------------
function LFightIdlePatrolAction:StartAction()
	self._nextCheckTime = 0
	self._phase = LFightIdlePatrolAction.PHASE_IDLE

	local waitTime = self._obj:GetPatrolWaitTime()
	if waitTime then
		self._waitTime = self:GetTime() + waitTime
	end

	self:CalcLimitArea()
end

function LFightIdlePatrolAction:CircleArea()
	self:CalcLimitArea()
end
-----------------------------------------------------------------
function LFightIdlePatrolAction:CalcLimitArea()
	if self._obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local limitArea = self._obj:GetMonMoveArea()
		local birthPos = self._obj:GetBirthPos()
		local limitMin = birthPos.x + limitArea.min
		local limitMax = birthPos.x + limitArea.max
		self._limitArea = {min=limitMin,max=limitMax}
	end
end

-----------------------------------------------------------------
function LFightIdlePatrolAction:GoToWait()
	self._phase = LFightIdlePatrolAction.PHASE_IDLE
	if self._obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local stayTimeLimit = self._obj:GetMonStayTime() or {}
		local min = stayTimeLimit.min or 0
		local max = stayTimeLimit.max or 0
		self._waitTime = self:GetTime() + math.random() * (max - min) + min
	elseif self._obj:GetObjType() == LFightIdleConst.OBJ_MISSION then
		local stayTimeLimit = self._obj:GetMonStayTime() or {}
		local min = stayTimeLimit.min or 3
		local max = stayTimeLimit.max or 3
		self._waitTime = self:GetTime() + math.random() * (max - min) + min
	else
		self._waitTime = self:GetTime() + math.random() * 1 + 0.5
	end

	self._obj:PlayIdleAni()
	self._obj:SetStatus(LFightIdleConst.STATUS_IDLE)
end
-----------------------------------------------------------------
function LFightIdlePatrolAction:GotoPatrol()
	local obj = self._obj

	local pos = obj:GetPosition()
	local nowX = pos.x

	local minPos,maxPos = self._obj:GetPathData()

	local minX = minPos.x
	local maxX = maxPos.x

	local speed = obj:GetMoveSpeed()
	if obj:GetObjType() == LFightIdleConst.OBJ_MON then
		local speedRate = obj:GetMonMoveSpeedRate() or 1
		speed = speed * speedRate
		local limitArea = self._limitArea
		local limitMin = limitArea.min
		local limitMax = limitArea.max
		minX = Mathf.Max(limitMin,minX)
		maxX = Mathf.Min(limitMax,maxX)
	end

	local dir = obj:GetDirection()

	local targetX = 0
	--靠近左边 朝右边行走
	if LFightIdleConst.Approximately(nowX,minX) then
		targetX = maxX
	--靠近右边，朝左边行走
	elseif LFightIdleConst.Approximately(nowX,maxX) then
		targetX = minX
	else
		--朝远的点行走
		if Mathf.Abs(maxX - nowX) < Mathf.Abs(minX - nowX) then
			targetX = minX
		else
			targetX = maxX
		end
	end

	local actor = obj:GetMoveActor()

	local time = Mathf.Abs(targetX - nowX) / speed * 100

	local tarPos = Vector3(targetX,pos.y,pos.z)
	actor:MoveTo(tarPos,time)

	obj:SetStatus(LFightIdleConst.STATUS_MOVE)
	obj:PlayRunAni()

	obj:ChangeDirToPos(tarPos)

	self._phase = LFightIdlePatrolAction.PHASE_MOVE
end
-----------------------------------------------------------------

function LFightIdlePatrolAction:StopAction()

end

function LFightIdlePatrolAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end


return LFightIdlePatrolAction